function Logo({ size = "md", onClick }) {
  const h = size === "lg" ? 140 : size === "sm" ? 40 : 150;
  return (
    <img
      src={LOGO_IMG}
      alt="ZentriqFlow"
      onClick={onClick}
      style={{
        height: h,
        width: "auto",
        cursor: onClick ? "pointer" : "default",
      }}
    />
  );
}

function QRCode({ url, size = 160 }) {
  const src = `https://api.qrserver.com/v1/create-qr-code/?size=${size}x${size}&data=${encodeURIComponent(
    url
  )}`;
  return (
    <img
      src={src}
      alt="QR Code"
      style={{
        width: size,
        height: size,
        borderRadius: 12,
        border: `2px solid ${BRAND.blueMid}`,
      }}
    />
  );
}

